#!/usr/bin/env node

import { execFileSync } from "node:child_process";
import { mkdtempSync, rmSync, writeFileSync } from "node:fs";
import { join } from "node:path";
import { tmpdir } from "node:os";

const privateKey = process.env.TAURI_SIGNING_PRIVATE_KEY ?? "";

if (!privateKey.trim()) {
  fail(
    [
      "Missing TAURI_SIGNING_PRIVATE_KEY.",
      "Add it as a GitHub Actions repository secret before publishing updater-enabled releases.",
      "The secret value must be the one-line base64 private key generated by `pnpm exec tauri signer generate`.",
    ].join("\n"),
  );
}

if (privateKey !== privateKey.trim() || /\s/.test(privateKey)) {
  fail(
    [
      "TAURI_SIGNING_PRIVATE_KEY must be a single base64 value without spaces or newlines.",
      "Use the private key value generated by `pnpm exec tauri signer generate` without decoding it.",
    ].join("\n"),
  );
}

if (/^untrusted comment:/m.test(privateKey) || /^trusted comment:/m.test(privateKey)) {
  fail(
    [
      "TAURI_SIGNING_PRIVATE_KEY appears to be decoded minisign text.",
      "Use the one-line base64 private key value generated by the Tauri CLI instead.",
    ].join("\n"),
  );
}

const tempDir = mkdtempSync(join(tmpdir(), "wovo-updater-signing-"));
const probeFile = join(tempDir, "probe.txt");

try {
  writeFileSync(probeFile, "WoVo updater signing preflight\n", "utf8");

  const pnpm = process.platform === "win32" ? "pnpm.cmd" : "pnpm";
  execFileSync(pnpm, ["exec", "tauri", "signer", "sign", probeFile], {
    env: process.env,
    stdio: ["ignore", "ignore", "pipe"],
  });

  console.log("Validated updater signing secrets.");
} catch (error) {
  const stderr = error.stderr?.toString("utf8").trim();
  fail(
    [
      "Updater signing secret validation failed.",
      stderr || error.message,
      "Confirm that TAURI_SIGNING_PRIVATE_KEY matches the updater pubkey in src-tauri/tauri.conf.json.",
      "If the key was generated with a password, set TAURI_SIGNING_PRIVATE_KEY_PASSWORD to that exact password.",
    ].join("\n"),
  );
} finally {
  rmSync(tempDir, { recursive: true, force: true });
}

function fail(message) {
  console.error(message);
  process.exit(1);
}
